// Parse the LLM response: article markdown + metadata JSON
const output = $input.first().json.output;
const articleData = $('Read Article').first().json;

// Split on the metadata separator
const parts = output.split('---METADATA---');
const markdown = parts[0].trim();

let metadata = {
  meta_description: '',
  keywords: [],
  visual_suggestions: []
};

if (parts.length > 1) {
  try {
    const metaStr = parts[1].replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    metadata = JSON.parse(metaStr);
  } catch (e) {
    console.log('Warning: Could not parse metadata JSON, using defaults. Error:', e.message);
  }
}

// Convert markdown to HTML
function mdToHtml(md) {
  let html = md;
  // Headings (h3 before h2 before h1 to avoid conflicts)
  html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
  html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');
  // Bold and italic
  html = html.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
  // Blockquotes
  html = html.replace(/^> (.+)$/gm, '<blockquote>$1</blockquote>');
  // Unordered lists
  html = html.replace(/^- (.+)$/gm, '<li>$1</li>');
  html = html.replace(/((?:<li>.*<\/li>\n?)+)/g, '<ul>$1</ul>');
  // Ordered lists
  html = html.replace(/^\d+\. (.+)$/gm, '<li>$1</li>');
  // Links
  html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  // Paragraphs: wrap remaining plain text lines
  html = html.split('\n\n').map(block => {
    const trimmed = block.trim();
    if (!trimmed) return '';
    if (/^<(h[1-3]|ul|ol|blockquote|li)/.test(trimmed)) return trimmed;
    return '<p>' + trimmed.replace(/\n/g, ' ') + '</p>';
  }).join('\n');
  return html;
}

const draftHtml = mdToHtml(markdown);

return [{
  json: {
    article_id: articleData.id,
    draft_html: draftHtml,
    meta_description: metadata.meta_description || '',
    keywords: metadata.keywords || [],
    visual_suggestions: metadata.visual_suggestions || [],
    status: 'draft'
  }
}];

